#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int V[n], P[n], C[m], D[m];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &V[i], &P[i]);
        }
        for (int i = 0; i < m; i++) {
            scanf("%d %d", &C[i], &D[i]);
        }
        double expected = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            double prob = 1;
            int money = 0, diamonds = 0;
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    prob *= P[i] / 100.0;
                    money += V[i];
                } else {
                    prob *= (100 - P[i]) / 100.0;
                    diamonds++;
                }
            }
            int count = 0;
            for (int i = 0; i < m; i++) {
                if (money >= C[i] && diamonds >= D[i]) {
                    count++;
                    money -= C[i];
                    diamonds -= D[i];
                }
            }
            expected += count * prob;
        }
        printf("%.4f\n", expected);
    }
    return 0;
}

