const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [n, m] = readline().split(' ').map(Number);
    const V = new Array(n);
    const P = new Array(n);
    const C = new Array(m);
    const D = new Array(m);
    for (let j = 0; j < n; j++) {
        [V[j], P[j]] = readline().split(' ').map(Number);
    }
    for (let j = 0; j < m; j++) {
        [C[j], D[j]] = readline().split(' ').map(Number);
    }
    let expected = 0;
    for (let mask = 0; mask < (1 << n); mask++) {
        let prob = 1;
        let money = 0;
        let diamonds = 0;
        for (let j = 0; j < n; j++) {
            if ((mask & (1 << j)) !== 0) {
                prob *= P[j] / 100;
                money += V[j];
            } else {
                prob *= (100 - P[j]) / 100;
                diamonds++;
            }
        }
        let count = 0;
        for (let j = 0; j < m; j++) {
            if (money >= C[j] && diamonds >= D[j]) {
                count++;
                money -= C[j];
                diamonds -= D[j];
            }
        }
        expected += count * prob;
    }
    console.log(expected.toFixed(4));
}
